INSERT INTO `tipo_observacion` VALUES (1, 'Licencias y Permisos', 'Falta o vencimiento de licencias operativas, permisos sanitarios o de funcionamiento requeridos por la ley.', 6, 1, 'ALTA', 120, 1);
INSERT INTO `tipo_observacion` VALUES (2, 'Protección de Datos', 'Incumplimiento de políticas de protección de datos personales de clientes o empleados', 5, 1, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (3, 'Ética Empresarial', 'Reportes de falta de apego al código de ética o políticas de conflicto de interés por parte del personal.', 5, 1, 'ALTA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (4, 'Documentación de Registros', 'Bitácora de cloración desactualizada o falta de actualización de otros registros.', 1, 1, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (5, 'Plano y Señalización', 'Plano de distribución de áreas no actualizado, señalización deteriorada o faltante.', 7, 1, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (6, 'Auditoría Interna', 'Hallazgos de auditoría relacionados con la falta de apego a políticas internas o procedimientos específicos.', 1, 1, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (7, 'Documentación de Residuos', 'Falta de documentos que acrediten la recolección y disposición adecuada de residuos peligrosos (RPBI).', 9, 1, 'ALTA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (8, 'Contratos Vencidos', 'Contratos con proveedores, servicios o personal que han expirado y no han sido renovados.', 6, 1, 'MEDIA', 96, 1);
INSERT INTO `tipo_observacion` VALUES (9, 'Regulaciones de Almacenamiento', 'Incumplimiento de normativas para el almacenamiento de productos, como temperatura o humedad inadecuadas.', 9, 1, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (10, 'Certificaciones de Calidad', 'Falta de certificación o auditorías internas de calidad requeridas para productos o procesos.', 1, 1, 'BAJA', 168, 1);
INSERT INTO `tipo_observacion` VALUES (11, 'Recetas sin Retener', 'Falta de retención de recetas médicas como lo establecen los protocolos.', 14, 1, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (12, 'Gestión de Licitaciones', 'Falta de conocimiento y seguimiento sobre el proceso de recolección de productos de licitaciones.', 9, 1, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (13, 'Falta de Protocolos de Emergencia', 'El personal desconoce los protocolos de actuación ante incendios, sismos o emergencias médicas.', 2, 1, 'ALTA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (14, 'Uso Incorrecto de Uniforme', 'El personal no utiliza el uniforme completo o lo usa en mal estado.', 2, 1, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (15, 'Riesgos de Seguridad', 'Condiciones inseguras en las instalaciones, como salidas de emergencia bloqueadas o cableado expuesto.', 7, 2, 'CRITICA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (16, 'Condiciones de Higiene', 'Deficiencias en la limpieza y sanidad de áreas comunes, baños o zonas de preparación de alimentos.', 7, 2, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (17, 'Manejo de Residuos Biológicos', 'Recipiente para residuos peligrosos biológico-infecciosos (RPBI) en mal estado o manejo inadecuado de desechos.', 9, 2, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (18, 'Mantenimiento de Equipo de Emergencia', 'Botiquines incompletos, extintores sin revisión o señalización de rutas de evacuación deteriorada.', 7, 2, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (19, 'Condiciones Ergonómicas', 'Puestos de trabajo que no cumplen con los estándares ergonómicos, generando riesgos para la salud del personal.', 2, 2, 'MEDIA', 96, 1);
INSERT INTO `tipo_observacion` VALUES (20, 'Uso de EPP', 'Incumplimiento del personal en el uso adecuado del Equipo de Protección Personal (EPP).', 11, 2, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (21, 'Falta de Extintores', 'No se cuenta con extintores o los existentes no tienen la recarga adecuada o están fuera de su ubicación.', 7, 2, 'CRITICA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (22, 'Accesos Seguros', 'Accesos a áreas restringidas sin control o con candados rotos.', 7, 2, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (23, 'Riesgos en el Almacén', 'Pasillos de almacén obstruidos, materiales apilados de forma insegura, o falta de señalización de riesgos.', 9, 2, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (24, 'Fallas de Infraestructura General', 'Problemas en baños, tuberías, mobiliario o equipos electrónicos, como tuberías rotas o baños sin funcionar.', 7, 7, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (25, 'Daños en la Estructura', 'Paredes deterioradas, con desprendimiento de pintura o con aberturas.', 7, 7, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (26, 'Fallas en Iluminación', 'Lámparas o luces que no funcionan correctamente.', 7, 7, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (27, 'Limpieza y Orden', 'Falta de limpieza y orden en áreas de la farmacia o consultorio, como polvo en anaqueles o excremento de aves.', 7, 7, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (28, 'Daño en Mobiliario', 'Anaqueles rayados, mostradores dañados o puertas que no cierran bien.', 7, 7, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (29, 'Condiciones Ambientales', 'Problemas con el aire acondicionado o ventilación. También se menciona que los frigobares no funcionan, lo que afecta productos que requieren refrigeración.', 7, 7, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (30, 'Faltante de Inventario', 'Discrepancias entre el inventario físico y el registrado en el sistema, resultando en pérdidas de productos.', 8, 8, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (31, 'Sobrante de Inventario', 'Sobrantes de productos en el inventario.', 8, 8, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (32, 'Productos Caducados en Anaquel', 'Detección de productos expirados en anaqueles, sin haber sido retirados a tiempo.', 8, 8, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (33, 'Inventario en Mal Estado', 'Productos dañados, defectuosos o que no cumplen con los estándares de calidad.', 8, 8, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (34, 'Procesos de Devolución', 'Retraso en el procesamiento de devoluciones, afectando la conciliación de inventario y la satisfacción del cliente.', 9, 8, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (35, 'Rotación de Inventario (PEPS)', 'No se aplica el principio de Primeras Entradas, Primeras Salidas, lo que puede llevar a la caducidad de productos.', 8, 8, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (36, 'Productos sin Etiquetar', 'Productos sin etiquetas de precio o información de lote y caducidad.', 14, 8, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (37, 'Ausentismo del Personal', 'Incidencias de ausentismo no justificado que afectan la operación diaria de la empresa.', 2, 4, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (38, 'Incidencias de Personal', 'Conductas del personal que no cumplen con las normativas, como cobros no autorizados.', 2, 4, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (39, 'Documentación de Expedientes', 'Falta de documentos requeridos en los expedientes de personal.', 2, 4, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (40, 'Capacitación Faltante', 'Personal que no ha recibido la capacitación obligatoria para su puesto o sobre nuevos procesos y herramientas.', 2, 4, 'BAJA', 168, 1);
INSERT INTO `tipo_observacion` VALUES (41, 'Clima Laboral Negativo', 'Reportes o quejas sobre un ambiente de trabajo que afecta la moral o la productividad del equipo.', 2, 4, 'MEDIA', 96, 1);
INSERT INTO `tipo_observacion` VALUES (42, 'Actitud de Servicio', 'Comportamientos del personal que demuestran una mala actitud de servicio al cliente.', 2, 4, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (43, 'Incumplimiento de Horarios', 'Incumplimiento en los horarios de entrada y salida, afectando la operatividad.', 2, 4, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (44, 'Falta de Cobertura en Turnos', 'Ausencia de personal en un turno, dejando la operación desatendida.', 2, 4, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (45, 'Fallas en Sistemas y Red', 'Problemas con la conectividad a internet, el funcionamiento de impresoras o fallas en terminales.', 12, 5, 'CRITICA', 12, 1);
INSERT INTO `tipo_observacion` VALUES (46, 'Mal uso de Software', 'Personal utilizando software no autorizado o sistemas de manera inadecuada, comprometiendo la seguridad de la información.', 12, 5, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (47, 'Seguridad de la Información', 'Fugas de información confidencial o acceso no autorizado a sistemas y documentos de la empresa.', 12, 5, 'CRITICA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (48, 'Equipos sin Mantenimiento', 'Equipos de cómputo o impresoras que no han recibido el mantenimiento preventivo programado.', 12, 5, 'BAJA', 168, 1);
INSERT INTO `tipo_observacion` VALUES (49, 'Software Obsoleto', 'Uso de versiones de software antiguas o sin actualizaciones de seguridad.', 12, 5, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (50, 'Fallas en Cámaras de Seguridad', 'Cámaras de seguridad que no funcionan o no graban correctamente.', 12, 5, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (51, 'Facturación Incorrecta', 'Errores en la emisión de facturas a clientes, afectando la contabilidad y la relación comercial.', 3, 6, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (52, 'Conciliación Bancaria', 'Pendientes en la conciliación de ventas o depósitos bancarios, que podrían indicar errores contables.', 3, 6, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (53, 'Gastos sin Comprobar', 'Falta de facturas o tickets que justifiquen gastos empresariales, dificultando la contabilidad y auditoría.', 3, 6, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (54, 'Reportes Financieros Atrasados', 'No se cumplen los plazos para la entrega de reportes financieros o de ventas.', 3, 6, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (55, 'Inconsistencias en Cobranza', 'Discrepancias en los pagos de clientes que no han sido registrados o conciliados correctamente.', 3, 6, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (56, 'Descuadre de Caja', 'Discrepancias entre el efectivo físico y el registrado en los reportes de cierre de caja.', 13, 10, 'CRITICA', 12, 1);
INSERT INTO `tipo_observacion` VALUES (57, 'Fallas en la Facturación y Ventas', 'Descuadres de caja, ya sea por faltante o sobrante de efectivo, o fallas en el sistema de ventas.', 13, 10, 'CRITICA', 12, 1);
INSERT INTO `tipo_observacion` VALUES (58, 'Discrepancias en Nómina', 'Errores en los registros de nómina que pueden resultar en pagos incorrectos al personal.', 10, 10, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (60, 'Faltante en Fondo Fijo (Caja Chica)', 'Discrepancia negativa en el arqueo del fondo fijo de efectivo.', 13, 1, 'CRITICA', 8, 1);
INSERT INTO `tipo_observacion` VALUES (61, 'Sobrante en Fondo Fijo (Caja Chica)', 'Discrepancia positiva en el arqueo del fondo fijo de efectivo.', 13, 1, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (62, 'Faltante en Venta del Día', 'Diferencia negativa detectada en el arqueo de la venta diaria.', 13, 1, 'ALTA', 12, 1);
INSERT INTO `tipo_observacion` VALUES (63, 'Sobrante en Venta del Día', 'Diferencia positiva detectada en el arqueo de la venta diaria.', 13, 1, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (64, 'Gastos no Autorizados por Tesorería', 'Se han registrado gastos en la caja chica sin la debida autorización del departamento de Tesorería.', 13, 1, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (65, 'Reposición de Gastos Pendiente', 'Solicitud de reposición de gastos de caja chica pendiente de ser procesada por Tesorería.', 13, 1, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (66, 'Depósitos Desfasados', 'La venta del día no fue depositada en la fecha correspondiente, generando un desfase en los registros.', 3, 1, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (67, 'Error en Registro de Cobro con Tarjeta', 'Venta cobrada con tarjeta de crédito/débito registrada incorrectamente como efectivo en el sistema.', 3, 1, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (68, 'Ficha de Depósito no Localizada', 'No se encuentra la ficha de depósito bancario correspondiente a la venta de una fecha específica.', 3, 1, 'ALTA', 12, 1);
INSERT INTO `tipo_observacion` VALUES (69, 'Venta Ficticia para Aprovechar Descuento', 'Se sospecha de la generación de ventas ficticias para beneficiarse de promociones o descuentos no aplicables.', 1, 1, 'CRITICA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (70, 'Faltante de Inventario', 'Diferencia negativa entre el inventario físico y el registrado en el sistema.', 8, 2, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (71, 'Sobrante de Inventario', 'Diferencia positiva entre el inventario físico y el registrado en el sistema.', 8, 2, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (72, 'Producto Caducado en Anaquel', 'Se encontró producto con fecha de caducidad vencida disponible para la venta en el anaquel.', 14, 2, 'CRITICA', 8, 1);
INSERT INTO `tipo_observacion` VALUES (73, 'Producto Próximo a Caducar sin Separar', 'Producto cercano a su fecha de vencimiento no ha sido retirado del anaquel para su devolución o gestión.', 14, 2, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (74, 'Producto Dañado en Anaquel', 'Mercancía con empaque o contenido dañado, no apta para la venta.', 14, 2, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (75, 'Ajuste de Inventario Pendiente', 'Solicitud de ajuste por faltante, sobrante o merma pendiente de ser aplicada por Control de Inventarios.', 8, 2, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (76, 'Producto Olvidado por Cliente sin Gestionar', 'Artículo olvidado por un cliente que no ha sido gestionado según el procedimiento establecido.', 14, 2, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (77, 'Error en Traspaso entre Sucursales', 'Se detectaron discrepancias en el inventario derivadas de un error en un traspaso de mercancía entre sucursales.', 9, 2, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (78, 'Devolución a CEDIS Pendiente', 'Producto que debía ser devuelto al Centro de Distribución (CEDIS) aún permanece en la sucursal.', 9, 2, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (79, 'Producto con Lote o Caducidad Ilegible', 'Artículo cuyo número de lote o fecha de caducidad no es visible o es ilegible.', 14, 2, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (80, 'Licencia de Funcionamiento Municipal Vencida', 'La licencia de funcionamiento emitida por el municipio se encuentra desactualizada.', 4, 3, 'CRITICA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (81, 'Receta Médica Mal Retenida', 'Retención incorrecta de una receta médica, incumpliendo la normativa para dispensación de medicamentos.', 1, 3, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (82, 'Falta de Bitácora de Cloración', 'Inexistencia o falta de actualización de la bitácora de cloración y desinfección del agua.', 7, 3, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (83, 'Control de Temperatura y Humedad Desactualizado', 'Registros de temperatura y humedad ambiental no actualizados conforme a la normativa.', 14, 3, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (84, 'Acrílico Portadocumentos en Mal Estado', 'El acrílico para exhibir documentos regulatorios (licencias, avisos) está roto, sucio o deteriorado.', 7, 3, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (85, 'Falta de Insumos en Botiquín de Primeros Auxilios', 'El botiquín de primeros auxilios no cuenta con todos los insumos requeridos por la normativa.', 2, 3, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (86, 'Frigobar para Medicamentos con Fallas', 'El refrigerador destinado a medicamentos que requieren cadena de frío presenta fallas o suciedad.', 7, 3, 'CRITICA', 12, 1);
INSERT INTO `tipo_observacion` VALUES (87, 'Venta de Antibiótico sin Retención de Receta', 'Dispensación de antibióticos sin la debida retención de la receta médica, incumpliendo una norma crítica.', 14, 3, 'CRITICA', 8, 1);
INSERT INTO `tipo_observacion` VALUES (88, 'PNO (Procedimientos Normalizados de Operación) Desactualizado', 'Los PNO no están actualizados a la última versión o carecen de las firmas requeridas.', 4, 3, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (89, 'Apéndice H Incompleto en Consultorio', 'El material y equipo médico listado en el Apéndice H del consultorio está incompleto.', 5, 3, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (90, 'Anuncio Luminoso Sucio o Dañado', 'Marquesina o anuncio bipolar con suciedad, daños o lámparas fundidas que afectan la imagen corporativa.', 7, 4, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (91, 'Fachada con Daños o Suciedad', 'Pintura desprendida, manchas, grafitis o suciedad en las paredes exteriores de la sucursal.', 7, 4, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (92, 'Mobiliario en Mal Estado (Anaqueles, Mostradores)', 'Anaqueles, cajoneras o mostradores con pintura desprendida, óxido o daños estructurales.', 7, 4, 'MEDIA', 96, 1);
INSERT INTO `tipo_observacion` VALUES (93, 'Plafón o Techo Dañado', 'Plafones rotos, manchados por humedad o con desprendimientos.', 7, 4, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (94, 'Lona o Publicidad Exterior en Mal Estado', 'Lonas de fachada o publicidad exterior rotas, decoloradas o en mal estado general.', 7, 4, 'BAJA', 120, 1);
INSERT INTO `tipo_observacion` VALUES (95, 'Placas de Señalización Deterioradas', 'Placas de horarios, \"Empuje/Deslice\" o informativas, decoloradas, rotas o en mal estado.', 7, 4, 'BAJA', 96, 1);
INSERT INTO `tipo_observacion` VALUES (96, 'Equipo de Aire Acondicionado con Fallas', 'El sistema de aire acondicionado no enfría correctamente o presenta fugas.', 7, 4, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (97, 'Falla en Equipo (Ventiladores, Bocinas)', 'Ventiladores, bocinas u otros equipos menores no funcionan correctamente.', 7, 4, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (98, 'Mobiliario de Consultorio Deteriorado', 'Escritorio, silla, cama de exploración o báscula del consultorio en mal estado u oxidado.', 7, 4, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (99, 'Falta de Limpieza General en Sucursal', 'Se observa suciedad, polvo o falta de orden generalizada en las instalaciones de la farmacia o consultorio.', 14, 4, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (100, 'Incumplimiento de Meta de Venta (Cronograma)', 'La sucursal no alcanzó la meta de ventas establecida en el cronograma del mes anterior.', 14, 5, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (101, 'Lista de Precios Desactualizada', 'La lista de precios impresa en farmacia no corresponde al último anexo modificatorio.', 14, 5, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (102, 'Publicidad no Vigente Exhibida', 'Material publicitario de campañas pasadas sigue exhibido en la sucursal.', 14, 5, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (103, 'Protocolo de Atención al Cliente Incompleto', 'El personal no sigue el protocolo completo de atención al cliente (ej. no mencionar frase SDR o CEPIP).', 14, 5, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (104, 'Exhibición de Producto Incompleta', 'Faltan productos en las exhibiciones especiales aunque se cuenta con existencia en inventario.', 14, 5, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (105, 'Falta de Cancelaría o Aire Acondicionado', 'La farmacia carece de cancelería o aire acondicionado, lo que provoca acumulación de polvo y calor excesivo.', 7, 5, 'ALTA', 120, 1);
INSERT INTO `tipo_observacion` VALUES (106, 'Devolución de Cliente sin Aplicar', 'Una devolución de cliente reportada a Control de Inventarios aún no ha sido aplicada en el sistema.', 8, 5, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (107, 'Cierre de Sucursal Fuera de Horario', 'La farmacia cerró antes del horario establecido sin una justificación válida o autorización.', 4, 5, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (108, 'Falta de Insumos de Limpieza y Sanitarios', 'Desabasto de insumos básicos como jabón para manos, toallas sanitas o papel higiénico.', 14, 5, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (109, 'Timer de Anuncios Desprogramado', 'El temporizador que controla el encendido y apagado de los anuncios luminosos está desprogramado.', 7, 5, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (110, 'Organigrama Desactualizado', 'El organigrama de la sucursal no está actualizado con los nombres del personal vigente.', 2, 6, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (111, 'Gafetes de Personal en Mal Estado', 'Los gafetes de identificación del personal se encuentran rotos, ilegibles o en mal estado.', 2, 6, 'BAJA', 96, 1);
INSERT INTO `tipo_observacion` VALUES (112, 'Personal sin Gafete de Identificación', 'Colaborador(es) laborando sin portar su gafete de identificación oficial.', 2, 6, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (113, 'Uso Incorrecto de Uniforme', 'Personal utilizando prendas no autorizadas o el uniforme en mal estado (sucio, roto, sin botones).', 2, 6, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (114, 'Falta de Capacitación en Procesos Clave', 'Se detecta desconocimiento del personal en procedimientos críticos (manejo de recetas, inventarios, etc.).', 2, 6, 'ALTA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (115, 'Falta de Médico en Consultorio', 'El consultorio anexo a la farmacia no cuenta con un médico asignado o presente durante su turno.', 5, 6, 'CRITICA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (116, 'Actas Administrativas Pendientes de Aplicar', 'Se requiere la aplicación de actas administrativas por incumplimientos detectados previamente.', 2, 6, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (117, 'Consumo de Alimentos en Áreas no Permitidas', 'Personal consumiendo alimentos o bebidas en áreas no designadas para ello, como el punto de venta.', 14, 6, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (118, 'Productos Personales en Áreas de Trabajo', 'Se encuentran artículos personales de los colaboradores en áreas operativas de la farmacia.', 14, 6, 'BAJA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (119, 'Falta de Personal para Cubrir Turnos', 'Insuficiencia de personal que resulta en turnos descubiertos o sobrecarga de trabajo.', 2, 6, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (120, 'Falla en Equipo de Cómputo (PC)', 'Computadora de punto de venta presenta fallas, lentitud o no funciona.', 12, 7, 'CRITICA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (121, 'Falla en Periféricos (Lector, Teclado, Mouse)', 'Lector de código de barras, teclado o mouse de un equipo de cómputo no funciona correctamente.', 12, 7, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (122, 'Falla en Impresora', 'La impresora de tickets o de reportes presenta fallas de impresión o no funciona.', 12, 7, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (123, 'Falla en Terminal Bancaria (TPV)', 'La terminal para cobro con tarjeta presenta fallas de conexión o de batería.', 12, 7, 'CRITICA', 12, 1);
INSERT INTO `tipo_observacion` VALUES (124, 'Falla en \"No Break\" (UPS)', 'El sistema de alimentación ininterrumpida (No Break) no funciona, poniendo en riesgo los equipos.', 12, 7, 'ALTA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (125, 'Problemas de Conexión a Internet', 'La sucursal presenta intermitencia o falta total del servicio de internet.', 12, 7, 'CRITICA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (126, 'Reloj Checador no Funcional', 'El reloj checador de asistencia del personal no funciona o está desconfigurado.', 12, 7, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (127, 'Sistema SPOS con Fallas', 'El sistema de punto de venta (SPOS) presenta errores, lentitud o se bloquea.', 12, 7, 'CRITICA', 12, 1);
INSERT INTO `tipo_observacion` VALUES (128, 'Falta de Tóner para Impresora', 'La sucursal no cuenta con cartuchos de tóner de repuesto para la impresora.', 12, 7, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (129, 'Gaveta de Dinero no Funciona', 'La gaveta de dinero no abre correctamente de forma automática o con la llave.', 12, 7, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (130, 'Falla en Iluminación de Anuncio (Marquesina)', 'Lámparas fundidas, dañadas o con alineación incorrecta en el anuncio de marquesina.', 7, 8, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (131, 'Falla en Iluminación de Anuncio (Cruz)', 'Lámparas fundidas, daño en lona o colores desgastados en el anuncio de Cruz 24hrs.', 7, 8, 'ALTA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (132, 'Falla en Iluminación de Anuncio (Carita)', 'Zonas oscuras, lámparas fundidas, lona sucia, opaca o con tonos incorrectos en el anuncio de carita.', 7, 8, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (133, 'Falla en Iluminación de Anuncio (Bipolar/Poste)', 'Lámparas internas fundidas o daño en la lona del anuncio bipolar o de poste peatonal.', 7, 8, 'MEDIA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (134, 'Reflector Exterior Fundido', 'Uno o más reflectores que iluminan la fachada o anuncios se encuentran fundidos o no funcionan.', 7, 8, 'MEDIA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (135, 'Lona de Anuncio Deteriorada o Sucia', 'Lona de anuncio rota, desgastada, percudida o con colores incorrectos que requiere limpieza o cambio.', 7, 8, 'BAJA', 120, 1);
INSERT INTO `tipo_observacion` VALUES (136, 'Falta de Limpieza en Anuncios', 'Anuncios luminosos o de poste requieren limpieza general por acumulación de suciedad o eses de aves.', 7, 8, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (137, 'Timer de Anuncios Desprogramado', 'Se requiere reprogramar o reparar el encendido y apagado automático de los anuncios luminosos.', 7, 8, 'BAJA', 72, 1);
INSERT INTO `tipo_observacion` VALUES (138, 'Daño por Humedad en Infraestructura', 'Se observan áreas dañadas por humedad en paredes o techos que requieren mantenimiento correctivo.', 7, 8, 'ALTA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (139, 'Acumulación de Basura en Exteriores', 'Acumulación de basura o desechos en espacios aledaños a la farmacia, afectando la imagen corporativa.', 14, 8, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (140, 'Cableado Exterior Expuesto o Mal Gestionado', 'Se observa cableado expuesto o mal organizado en la fachada o anuncios, generando una mala imagen.', 7, 8, 'BAJA', 96, 1);
INSERT INTO `tipo_observacion` VALUES (141, 'Incumplimiento de Estrategia de Venta', 'El personal no ejecuta o no refuerza correctamente la estrategia de venta vigente (frase, degustación, promoción).', 14, 8, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (142, 'Exhibición de Producto Incompleta o Incorrecta', 'El acomodo de productos o la falta de mercancía en exhibiciones no cumple con el boletín o la estrategia actual.', 14, 8, 'MEDIA', 24, 1);
INSERT INTO `tipo_observacion` VALUES (143, 'Falta de Insumos para Operación o Promoción', 'Carencia de insumos necesarios para la operación diaria o para ejecutar promociones (ej. cinta, vasos para degustación).', 14, 8, 'BAJA', 48, 1);
INSERT INTO `tipo_observacion` VALUES (144, 'Falta de Personal en Turno', 'Insuficiencia de personal en turno, lo que afecta la correcta atención al cliente y la operación de la farmacia.', 2, 8, 'ALTA', 48, 1);
